//!
//! Provides P2P networking via iroh, including global matchmaking, chat,
//! direct messaging, echo protocol, sleep management, and user identity.

/// Cryptographic bootstrap keys for bootstrap nodes.
pub mod _bootstrap_keys;

/// Random word generation for human-readable identifiers.
pub(crate) mod _random_word;

/// Chat system: global chat, direct messages, presence, tickets, and raw rooms.
pub mod chat;

/// Echo protocol for latency measurement and connectivity testing.
pub mod echo;

/// Global matchmaker: bootstrap, global chat, matchmaking, and user identity.
pub mod global_matchmaker;

/// Main P2P node handling connections, endpoints, and gossip.
pub mod main_node;

/// Network manager configuration and setup.
pub mod network_manager;

/// Signed message serialization and verification.
pub(crate) mod signed_message;

/// Sleep/wake management for power-efficient P2P.
pub mod sleep;

/// User identity management: keys, secrets, and derived identities.
pub mod user_identity;

