/// Presence status flag for a peer in chat.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum PresenceFlag {
    /// Peer is actively present.
    ACTIVE,
    /// Peer has not sent presence recently.
    IDLE,
    /// Peer's presence has expired.
    EXPIRED,
    /// Peer presence is unconfirmed.
    UNCONFIRMED,
}

impl PresenceFlag {
    /// Create PresenceFlag from timestamp.
    pub fn from_instant(instant: i64) -> Self {
        let now = get_timestamp_now_ms();
        let elapsed = now - instant;
        if elapsed > PRESENCE_EXPIRATION.as_millis() as i64 {
            PresenceFlag::EXPIRED
        } else if elapsed > PRESENCE_IDLE.as_millis() as i64 {
            PresenceFlag::IDLE
        } else {
            PresenceFlag::ACTIVE
        }
    }
}

